# Helper for structured writing of values into a RustBuffer.
class RustBufferBuilder
  def initialize
    @rust_buf = RustBuffer.alloc 16
    @rust_buf.len = 0
  end

  def finalize
    rbuf = @rust_buf

    @rust_buf = nil

    rbuf
  end

  def discard
    return if @rust_buf.nil?

    rbuf = finalize
    rbuf.free
  end

  def write(value)
    reserve(value.bytes.size) do
      @rust_buf.data.put_array_of_char @rust_buf.len, value.bytes
    end
  end

  def write_U32(v)
    v = Mob::uniffi_in_range(v, "u32", 0, 2**32)
    pack_into(4, 'L>', v)
  end

  def write_U64(v)
    v = Mob::uniffi_in_range(v, "u64", 0, 2**64)
    pack_into(8, 'Q>', v)
  end

  def write_I64(v)
    v = Mob::uniffi_in_range(v, "i64", -2**63, 2**63)
    pack_into(8, 'q>', v)
  end

  def write_Bool(v)
    pack_into(1, 'c', v ? 1 : 0)
  end

  def write_String(v)
    v = Mob::uniffi_utf8(v)
    pack_into 4, 'l>', v.bytes.size
    write v
  end

  def write_Bytes(v)
    v = Mob::uniffi_bytes(v)
    pack_into 4, 'l>', v.bytes.size
    write v
  end

  # The Object type Client.

  def write_TypeClient(obj)
    handle = Client.uniffi_lower obj
    pack_into(8, 'Q>', handle)
  end

  # The Object type Signer.

  def write_TypeSigner(obj)
    handle = Signer.uniffi_lower obj
    pack_into(8, 'Q>', handle)
  end

  # The Record type AccountInfo.

  def write_TypeAccountInfo(v)
    self.write_String(v.address)
    self.write_U64(v.account_number)
    self.write_U64(v.sequence)
    self.write_Optionalstring(v.pub_key)
  end

  # The Record type ChainConfig.

  def write_TypeChainConfig(v)
    self.write_String(v.chain_id)
    self.write_String(v.rpc_endpoint)
    self.write_Optionalstring(v.grpc_endpoint)
    self.write_String(v.address_prefix)
    self.write_U32(v.coin_type)
    self.write_String(v.gas_price)
  end

  # The Record type Coin.

  def write_TypeCoin(v)
    self.write_String(v.denom)
    self.write_String(v.amount)
  end

  # The Record type Fee.

  def write_TypeFee(v)
    self.write_SequenceTypeCoin(v.amount)
    self.write_U64(v.gas_limit)
    self.write_Optionalstring(v.payer)
    self.write_Optionalstring(v.granter)
  end

  # The Record type TxResponse.

  def write_TypeTxResponse(v)
    self.write_String(v.txhash)
    self.write_U32(v.code)
    self.write_String(v.raw_log)
    self.write_U64(v.gas_wanted)
    self.write_U64(v.gas_used)
    self.write_I64(v.height)
  end

  # The Enum type BroadcastMode.

  def write_TypeBroadcastMode(v)
    pack_into(4, 'l>', v)
 end
   

  

  # The Optional<T> type for string.

  def write_Optionalstring(v)
    if v.nil?
      pack_into(1, 'c', 0)
    else
      pack_into(1, 'c', 1)
      self.write_String(v)
    end
  end

  # The Sequence<T> type for TypeCoin.

  def write_SequenceTypeCoin(items)
    pack_into(4, 'l>', items.size)

    items.each do |item|
      self.write_TypeCoin(item)
    end
  end

  

  private

  def reserve(num_bytes)
    if @rust_buf.len + num_bytes > @rust_buf.capacity
      @rust_buf = RustBuffer.reserve(@rust_buf, num_bytes)
    end

    yield

    @rust_buf.len += num_bytes
  end

  def pack_into(size, format, value)
    reserve(size) do
      @rust_buf.data.put_array_of_char @rust_buf.len, [value].pack(format).bytes
    end
  end
end

