# These match the values from the uniffi::rustcalls module
CALL_SUCCESS = 0
CALL_ERROR = 1
CALL_PANIC = 2



class MobError
    Rpc = Class.new StandardError
    Transaction = Class.new StandardError
    Signing = Class.new StandardError
    KeyDerivation = Class.new StandardError
    Address = Class.new StandardError
    Serialization = Class.new StandardError
    InvalidInput = Class.new StandardError
    Account = Class.new StandardError
    Network = Class.new StandardError
    GasEstimation = Class.new StandardError
    InsufficientFunds = Class.new StandardError
    Timeout = Class.new StandardError
    Generic = Class.new StandardError

