  # Record type AccountInfo
class AccountInfo
  attr_reader :address, :account_number, :sequence, :pub_key

  def initialize(address:, account_number:, sequence:, pub_key:)
    @address = address
    @account_number = account_number
    @sequence = sequence
    @pub_key = pub_key
  end

  def ==(other)
    if @address != other.address
      return false
    end
    if @account_number != other.account_number
      return false
    end
    if @sequence != other.sequence
      return false
    end
    if @pub_key != other.pub_key
      return false
    end

    true
  end
end
  
