  class Client

  # A private helper for initializing instances of the class from a raw handle,
  # bypassing any initialization logic and ensuring they are GC'd properly.
  def self.uniffi_allocate(handle)
    inst = allocate
    inst.instance_variable_set :@handle, handle
    ObjectSpace.define_finalizer(inst, uniffi_define_finalizer_by_handle(handle, inst.object_id))
    return inst
  end

  # A private helper for registering an object finalizer.
  # N.B. it's important that this does not capture a reference
  # to the actual instance, only its underlying handle.
  def self.uniffi_define_finalizer_by_handle(handle, object_id)
    Proc.new do |_id|
      Mob.rust_call(
        :uniffi_mob_fn_free_client,
        handle
      )
    end
  end

  # A private helper for lowering instances into a raw handle.
  # This does an explicit typecheck, because accidentally lowering a different type of
  # object in a place where this type is expected, could lead to memory unsafety.
  def self.uniffi_check_lower(inst)
    if not inst.is_a? self
      raise TypeError.new "Expected a Client instance, got #{inst}"
    end
  end

  def uniffi_clone_handle()
    return Mob.rust_call(
      :uniffi_mob_fn_clone_client,
      @handle
    )
  end

  def self.uniffi_lower(inst)
    return inst.uniffi_clone_handle()
  end
  def initialize(config)
        config = config
        RustBuffer.check_lower_TypeChainConfig(config)
    handle = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_constructor_client_new,RustBuffer.alloc_from_TypeChainConfig(config))
    @handle = handle
    ObjectSpace.define_finalizer(self, self.class.uniffi_define_finalizer_by_handle(handle, self.object_id))
  end

  def self.new_with_signer(config, signer)
        config = config
        RustBuffer.check_lower_TypeChainConfig(config)
        signer = signer
        (Signer.uniffi_check_lower signer)
    # Call the (fallible) function before creating any half-baked object instances.
    # Lightly yucky way to bypass the usual "initialize" logic
    # and just create a new instance with the required handle.
    return uniffi_allocate(Mob.rust_call_with_error(MobError,:uniffi_mob_fn_constructor_client_new_with_signer,RustBuffer.alloc_from_TypeChainConfig(config),(Signer.uniffi_lower signer)))
  end
  

  def attach_signer(signer)
        _signer = _signer
        (Signer.uniffi_check_lower _signer)
      Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_attach_signer,uniffi_clone_handle(),(Signer.uniffi_lower _signer))
  end
  
  def execute_contract(contract_address, msg, funds, memo)
        contract_address = Mob::uniffi_utf8(contract_address)
        
        msg = Mob::uniffi_bytes(msg)
        
        funds = funds
        RustBuffer.check_lower_SequenceTypeCoin(funds)
        memo = (memo ? Mob::uniffi_utf8(memo) : nil)
        RustBuffer.check_lower_Optionalstring(memo)
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_execute_contract,uniffi_clone_handle(),RustBuffer.allocFromString(contract_address),RustBuffer.allocFromBytes(msg),RustBuffer.alloc_from_SequenceTypeCoin(funds),RustBuffer.alloc_from_Optionalstring(memo))
    return result.consumeIntoTypeTxResponse
  end
  def get_account(address)
        address = Mob::uniffi_utf8(address)
        
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_get_account,uniffi_clone_handle(),RustBuffer.allocFromString(address))
    return result.consumeIntoTypeAccountInfo
  end
  def get_all_balances(address)
        address = Mob::uniffi_utf8(address)
        
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_get_all_balances,uniffi_clone_handle(),RustBuffer.allocFromString(address))
    return result.consumeIntoSequenceTypeCoin
  end
  def get_balance(address, denom)
        address = Mob::uniffi_utf8(address)
        
        denom = Mob::uniffi_utf8(denom)
        
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_get_balance,uniffi_clone_handle(),RustBuffer.allocFromString(address),RustBuffer.allocFromString(denom))
    return result.consumeIntoTypeCoin
  end
  def get_chain_id()
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_get_chain_id,uniffi_clone_handle(),)
    return result.consumeIntoString
  end
  def get_height()
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_get_height,uniffi_clone_handle(),)
    return result.to_i
  end
  def get_tx(hash)
        hash = Mob::uniffi_utf8(hash)
        
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_get_tx,uniffi_clone_handle(),RustBuffer.allocFromString(hash))
    return result.consumeIntoTypeTxResponse
  end
  def is_synced()
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_is_synced,uniffi_clone_handle(),)
    return 1 == result
  end
  def send(to_address, amount, memo)
        to_address = Mob::uniffi_utf8(to_address)
        
        amount = amount
        RustBuffer.check_lower_SequenceTypeCoin(amount)
        memo = (memo ? Mob::uniffi_utf8(memo) : nil)
        RustBuffer.check_lower_Optionalstring(memo)
    result = Mob.rust_call_with_error(MobError,:uniffi_mob_fn_method_client_send,uniffi_clone_handle(),RustBuffer.allocFromString(to_address),RustBuffer.alloc_from_SequenceTypeCoin(amount),RustBuffer.alloc_from_Optionalstring(memo))
    return result.consumeIntoTypeTxResponse
  end
  
end
  
